const d = $('Webhook').item.json;
try {
  const fs = require('fs');
  const p = 'D:/Content OS/pc_data/leads.json';
  let arr = [];
  try { arr = JSON.parse(fs.readFileSync(p,'utf8')); } catch(e) {}
  arr.push({
    id: Date.now(),
    name: d.name || 'Неизвестно',
    contact: d.contact || '',
    niche: d.niche || '',
    source: 'telegram',
    stage: 'contacted',
    date: new Date().toLocaleDateString('ru-RU',{day:'2-digit',month:'2-digit'}),
    notes: 'Авто-парсинг: ' + (d.keyword || '')
  });
  fs.writeFileSync(p, JSON.stringify(arr, null, 2));
  return [{json:{status:'ok',name:d.name}}];
} catch(e) {
  return [{json:{status:'error',msg:e.message}}];
}
